const inItem = $input.first().json;
const rawText = String(inItem.request_text || '').trim();
const text = rawText || '뉴스 요약';
const defaults = { article_count: 5, topic: '최신 이슈', include_youtube: true };

let articleCount = defaults.article_count;
const countMatch = text.match(/(\d{1,2})\s*개/) || text.match(/\b(?:top|latest)\s*(\d{1,2})\b/i);
if (countMatch) {
  const raw = Number(countMatch[countMatch.length - 1]);
  if (Number.isFinite(raw)) articleCount = Math.max(1, Math.min(10, raw));
}

const normalizeTopic = (value) => String(value || '')
  .replace(/^["'`]+|["'`]+$/g, '')
  .replace(/\s+/g, ' ')
  .replace(/^(관련|주제)\s*/i, '')
  .replace(/\s*(뉴스|기사|소식|헤드라인|digest|summary|briefing?)\s*$/i, '')
  .trim()
  .slice(0, 80);

const inferTopic = (input) => {
  const s = String(input || '').trim();
  if (!s) return defaults.topic;

  const explicit = s.match(/(?:주제|topic)\s*[:=]?\s*([^\n,.]+)/i);
  if (explicit && explicit[1]) {
    const value = normalizeTopic(explicit[1]);
    if (value) return value;
  }

  const compactKr = s.match(/([가-힣A-Za-z0-9+#.&/\-]{2,40})\s*(?:뉴스|기사|헤드라인)/i);
  if (compactKr && compactKr[1]) {
    const candidate = normalizeTopic(compactKr[1]);
    if (candidate && !/(요약|정리|선정|최신|오늘|개)$/i.test(candidate)) return candidate;
  }

  const englishNews = s.match(/(?:news|headlines?)\s*(?:about|on|for)?\s*([a-z0-9+#.&/\- ]{2,50})/i);
  if (englishNews && englishNews[1]) {
    const candidate = normalizeTopic(englishNews[1]);
    if (candidate) return candidate;
  }

  const categories = [
    { re: /(스포츠|sport|nba|nfl|mlb|epl|축구|야구|농구|테니스|골프|올림픽)/i, topic: '스포츠' },
    { re: /(경제|금융|finance|market|stock|증시|주식|코인|crypto|환율)/i, topic: '경제' },
    { re: /(정치|politic|election|정부|대통령|의회|외교)/i, topic: '정치' },
    { re: /(과학|science|우주|연구|논문)/i, topic: '과학' },
    { re: /(기술|tech|it|startup|반도체|플랫폼)/i, topic: '기술' },
    { re: /(ai|인공지능|머신러닝|생성형)/i, topic: 'AI' },
    { re: /(엔터|연예|entertainment|movie|music|드라마)/i, topic: '엔터테인먼트' },
    { re: /(건강|의료|health|medicine|바이오)/i, topic: '건강' },
  ];

  for (const c of categories) {
    if (c.re.test(s)) return c.topic;
  }

  const stopWords = new Set([
    '뉴스', '기사', '요약', '정리', '선정', '노션', '유튜브', '링크', '포함', '제외',
    '해줘', '해주세요', '보내줘', '줘', '하고', '그리고', 'please', 'summarize', 'summary',
    'digest', 'top', 'latest', 'to', 'in', 'on', 'for', 'the', 'a', 'an', 'news', 'headlines',
  ]);

  const tokens = s
    .replace(/[^\p{L}\p{N}\s+#.&/\-]/gu, ' ')
    .split(/\s+/)
    .map((t) => t.trim())
    .filter((t) => t.length >= 2 && !stopWords.has(t.toLowerCase()));

  if (tokens.length) {
    return normalizeTopic(tokens.slice(0, 3).join(' ')) || defaults.topic;
  }

  return defaults.topic;
};

const topic = inferTopic(text) || defaults.topic;
const includeYoutube = !/(유튜브\s*(제외|빼|없)|without\s+youtube|youtube\s*off)/i.test(text);
const hasKorean = /[가-힣]/.test(`${topic} ${text}`);

return [{
  json: {
    ...inItem,
    request_text: text,
    article_count: articleCount,
    topic,
    topic_label: topic,
    topic_query: `${topic}${hasKorean ? ' 뉴스' : ' news'}`.trim(),
    include_youtube: includeYoutube,
    hl: hasKorean ? 'ko' : 'en-US',
    gl: hasKorean ? 'KR' : 'US',
    ceid: hasKorean ? 'KR:ko' : 'US:en',
  },
}];

const inItem = $input.first().json;
const req = ($items('Parse Request', 0, 0)?.[0]?.json) || {};
const rss = String(inItem.body ?? inItem.data ?? inItem.response ?? '');
const decode = (s = '') => s
  .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\s+/g, ' ')
  .trim();
const tag = (chunk, name) => {
  const re = new RegExp('<' + name + '(?:\\s[^>]*)?>([\\s\\S]*?)<\\/' + name + '>', 'i');
  const m = chunk.match(re);
  return m ? decode(m[1]) : '';
};
const itemRegex = /<item>([\s\S]*?)<\/item>/gi;
const seen = new Set();
const all = [];
let match;
while ((match = itemRegex.exec(rss)) !== null) {
  const chunk = match[1];
  const title = tag(chunk, 'title');
  const rawLink = tag(chunk, 'link');
  const description = tag(chunk, 'description').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const pubDate = tag(chunk, 'pubDate');
  const source = tag(chunk, 'source') || 'Unknown';
  if (!rawLink || !title) continue;

  let cleanedLink = rawLink;
  try {
    const u = new URL(rawLink);
    if (u.hostname.includes('news.google.com')) {
      u.searchParams.delete('oc');
      cleanedLink = u.toString();
    }
  } catch {}

  const dedupeKey = cleanedLink || rawLink;
  if (seen.has(dedupeKey)) continue;
  seen.add(dedupeKey);

  all.push({ title, link: cleanedLink, description, pubDate, source });
}

const N = Math.max(1, Math.min(10, Number(req.article_count || inItem.article_count || 5)));
const selected = all.slice(0, N);
if (selected.length === 0) {
  throw new Error('No RSS items extracted from source feed');
}

const topic = req.topic || inItem.topic || 'AI';
const includeYoutube = Boolean(req.include_youtube ?? inItem.include_youtube ?? true);
const scopeMarker = String(req.scope_marker || inItem.scope_marker || '');
const telegramChatId = String(req.telegram_chat_id || inItem.telegram_chat_id || '');
const telegramUpdateId = String(req.telegram_update_id || inItem.telegram_update_id || '');
const requestSource = String(req.request_source || inItem.request_source || 'program');

return selected.map((a, idx) => ({
  json: {
    index: idx + 1,
    title: a.title,
    link: a.link,
    source: a.source,
    pubDate: a.pubDate,
    description: a.description,
    topic,
    article_count: N,
    include_youtube: includeYoutube,
    scope_marker: scopeMarker,
    telegram_chat_id: telegramChatId,
    telegram_update_id: telegramUpdateId,
    request_source: requestSource,
  },
}));

const rows = $input.all();

const clamp = (s, n) => String(s || '').replace(/\s+/g, ' ').trim().slice(0, n);
const NOTE = '원문 접근 제한: RSS title/description 기반 요약';

const parseJsonSafely = (text) => {
  if (typeof text !== 'string') return null;
  let t = text.trim();
  t = t.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  try { return JSON.parse(t); } catch {}
  const m = t.match(/\{[\s\S]*\}/);
  if (m) {
    try { return JSON.parse(m[0]); } catch {}
  }
  return null;
};

const ENV = typeof $env === 'object' && $env ? $env : {};
const getEnv = (key, fallback = '') => {
  const value = ENV[key];
  if (value === undefined || value === null || value === '') return String(fallback || '');
  return String(value);
};

const OPENAI_API_KEY = getEnv('OPENAI_API_KEY', '').trim();
const GEMINI_API_KEY = getEnv('GEMINI_API_KEY', getEnv('GOOGLE_API_KEY', '')).trim();
const CODEX_API_KEY = getEnv('CODEX_API_KEY', OPENAI_API_KEY).trim();
const LLAMACPP_BASE_URL = getEnv('LLAMACPP_BASE_URL', 'http://127.0.0.1:8080').replace(/\/$/, '');

const OPENAI_MODEL = getEnv('OPENAI_SUMMARY_MODEL', 'gpt-4o-mini').trim();
const GEMINI_MODEL = getEnv('GEMINI_SUMMARY_MODEL', 'gemini-2.0-flash').trim();
const CODEX_MODEL = getEnv('CODEX_SUMMARY_MODEL', 'gpt-5-codex').trim();
const LLAMACPP_MODEL = getEnv('LLAMACPP_MODEL', 'qwen2.5-0.5b-instruct-q4_k_m.gguf').trim();
const ENABLE_LOCAL_LLAMACPP_FALLBACK = /^(1|true|yes|on)$/i.test(getEnv('ENABLE_LOCAL_LLAMACPP_FALLBACK', '0').trim());
const STEER_SUMMARY_BRIDGE_ENABLED = /^(1|true|yes|on)$/i.test(getEnv('STEER_SUMMARY_BRIDGE_ENABLED', '1').trim());
const STEER_API_BASE_URL = getEnv('STEER_API_BASE_URL', 'http://127.0.0.1:5680').replace(/\/$/, '');
const STEER_API_KEY = getEnv('STEER_API_KEY', '').trim();

const isGarbageLine = (s) => {
  const t = String(s || '').trim();
  if (!t) return true;
  if (/^\{|^\}|^\[|^\]/.test(t)) return true;
  if (/^"[a-zA-Z_]+"\s*:/.test(t)) return true;
  if (/^\-?\s*"?(title|link|source|pubDate|summary_bullets|why_it_matters|keywords|transparency_note)"?/i.test(t)) return true;
  return false;
};

const titleCore = (title, source) => {
  let t = String(title || '').trim();
  if (!t) return '';
  if (source) {
    const esc = String(source).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    t = t.replace(new RegExp(`\\s[-|]\\s${esc}$`, 'i'), '').trim();
  }
  t = t.replace(/\s[-|]\s[^-|]{2,40}$/, '').trim();
  return t;
};

const detectTheme = (title) => {
  const t = String(title || '').toLowerCase();
  if (/summit|policy|regulat|pledge|government|country|india|china|u\.s/.test(t)) return '정책/지정학';
  if (/invest|billion|fund|market|boom|chip|industry|company|startup/.test(t)) return '산업/투자';
  if (/model|safety|research|openai|google|anthropic|agent|benchmark/.test(t)) return '기술/연구';
  return '시장 동향';
};

const keywordFromText = (title) => {
  const stop = new Set(['the','and','for','with','from','that','this','into','over','after','before','about','what','your','you','are','was','were','will','has','have','had','news','today','more','than','between','their','they','its','not','so','much','at','in','on','to','of','a','an','is','as','by','it','ai']);
  const raw = String(title || '')
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .split(/\s+/)
    .map((x) => x.trim())
    .filter((x) => x.length >= 2 && !stop.has(x.toLowerCase()));
  const uniq = [];
  for (const t of raw) {
    if (!uniq.find((u) => u.toLowerCase() === t.toLowerCase())) uniq.push(t);
  }
  return uniq.slice(0, 3);
};

const heuristicSummary = (j) => {
  const core = titleCore(j.title || '', j.source || '') || String(j.title || '').trim();
  const theme = detectTheme(core);
  const datePart = String(j.pubDate || '').slice(0, 16) || '발행시각 미상';

  const bullets = [
    clamp(`핵심 이슈: "${core}" 관련 움직임이 관측되었습니다.`, 180),
    clamp(`맥락: ${j.source || 'Unknown'} 보도(${datePart}) 기준으로 ${theme} 관점의 중요 신호입니다.`, 180),
    clamp('체크포인트: 세부 수치·발표 주체·시점을 원문에서 추가 확인하세요.', 180),
  ];

  const kw = keywordFromText(core);
  while (kw.length < 3) kw.push(['AI', '시장', '동향'][kw.length]);

  return {
    title: clamp(j.title || core || '', 220),
    link: clamp(j.link || '', 500),
    source: clamp(j.source || 'Unknown', 120),
    pubDate: clamp(j.pubDate || '', 120),
    summary_bullets: bullets,
    why_it_matters: clamp(`${theme} 측면에서 후속 정책·투자·제품 전략에 영향을 줄 수 있어 추적 가치가 큽니다.`, 220),
    keywords: kw.slice(0, 3),
    transparency_note: NOTE,
    scope_marker: clamp(j.scope_marker || '', 120),
    telegram_chat_id: String(j.telegram_chat_id || ''),
    article_count: Number(j.article_count || 5),
  };
};

const overlapRatio = (text, titleWords) => {
  const words = String(text || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .split(/\s+/)
    .filter(Boolean);
  if (!words.length || !titleWords.length) return 0;
  const hit = words.filter((w) => titleWords.includes(w)).length;
  return hit / words.length;
};

const weakBullets = (bullets, title) => {
  if (!Array.isArray(bullets) || bullets.length < 3) return true;
  const cleaned = bullets.map((b) => String(b || '').trim()).filter(Boolean);
  if (cleaned.length < 3) return true;
  const koreanCount = cleaned.filter((b) => /[가-힣]/.test(b)).length;
  if (koreanCount < 2) return true;
  const titleWords = String(title || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .split(/\s+/)
    .filter((x) => x.length > 1);
  const copied = cleaned.filter((b) => overlapRatio(b, titleWords) > 0.75).length;
  if (copied >= 2) return true;
  return false;
};

const makePrompt = (j) => [
  '당신은 AI 뉴스 요약기입니다. 입력(title/link/source/pubDate/description)만 사용해 요약하세요.',
  'JSON 객체 하나만 출력하고, 코드블록/마크다운/설명문을 절대 추가하지 마세요.',
  'summary_bullets는 한국어 완결 문장 3~6개로 작성하세요(단어 나열 금지).',
  `transparency_note는 반드시 다음 문구 포함: "${NOTE}"`,
  '',
  '입력:',
  `- title: ${String(j.title || '')}`,
  `- link: ${String(j.link || '')}`,
  `- source: ${String(j.source || '')}`,
  `- pubDate: ${String(j.pubDate || '')}`,
  `- description: ${String(j.description || '')}`,
  '',
  '{',
  '  "title": "string",',
  '  "link": "string",',
  '  "source": "string",',
  '  "pubDate": "string",',
  '  "summary_bullets": ["string", "string", "string"],',
  '  "why_it_matters": "string",',
  '  "keywords": ["string", "string", "string"],',
  '  "transparency_note": "string",',
  '  "scope_marker": "string",',
  '  "telegram_chat_id": "string",',
  '  "article_count": 5',
  '}',
].join('\n');

const toErrorText = (data) => {
  if (!data) return '';
  if (typeof data === 'string') return data.slice(0, 220);
  const c = data.error?.message || data.message || data.error || '';
  return String(c).slice(0, 220);
};

const httpPostJson = async (url, headers, body) => {
  const options = {
    method: 'POST',
    url,
    headers: { 'content-type': 'application/json', ...headers },
    body,
    json: true,
    timeout: 60000,
  };
  try {
    if (typeof this !== 'undefined' && this?.helpers?.httpRequest) return await this.helpers.httpRequest(options);
    if (typeof $httpRequest === 'function') return await $httpRequest(options);
    throw new Error('HTTP_HELPER_NOT_AVAILABLE');
  } catch (err) {
    const status = err?.statusCode || err?.httpCode || '';
    const msg = err?.message || err?.description || toErrorText(err?.response?.body) || String(err);
    throw new Error(`HTTP_${status || 'ERR'}:${clamp(msg, 220)}`);
  }
};

const callOpenAI = async ({ apiKey, model, prompt }) => {
  const data = await httpPostJson('https://api.openai.com/v1/chat/completions', { authorization: `Bearer ${apiKey}` }, {
    model,
    temperature: 0.2,
    messages: [
      { role: 'system', content: 'Return only one valid JSON object. No markdown.' },
      { role: 'user', content: prompt },
    ],
  });
  const text = data?.choices?.[0]?.message?.content;
  if (!text) throw new Error('EMPTY_RESPONSE');
  return String(text);
};

const callGemini = async ({ apiKey, model, prompt }) => {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(model)}:generateContent?key=${encodeURIComponent(apiKey)}`;
  const data = await httpPostJson(url, {}, {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { temperature: 0.2, responseMimeType: 'application/json' },
  });
  const text = (data?.candidates || []).flatMap((c) => c?.content?.parts || []).map((p) => p?.text || '').join('\n').trim();
  if (!text) throw new Error('EMPTY_RESPONSE');
  return text;
};

const callLlamaCpp = async ({ baseUrl, model, prompt }) => {
  const data = await httpPostJson(`${baseUrl}/v1/chat/completions`, {}, {
    model,
    temperature: 0.2,
    messages: [
      { role: 'system', content: 'Return only one valid JSON object. No markdown.' },
      { role: 'user', content: prompt },
    ],
  });
  const text = data?.choices?.[0]?.message?.content;
  if (!text) throw new Error('EMPTY_RESPONSE');
  return String(text);
};

const callSteerSummaryBridge = async ({ baseUrl, apiKey, article }) => {
  const headers = {};
  if (apiKey) headers['X-API-Key'] = apiKey;
  const payload = {
    title: article.title || '',
    link: article.link || '',
    source: article.source || '',
    pubDate: article.pubDate || '',
    description: article.description || '',
    scope_marker: article.scope_marker || '',
    telegram_chat_id: article.telegram_chat_id || '',
    article_count: Number(article.article_count || 5),
    topic: article.topic || '뉴스',
  };
  const data = await httpPostJson(`${baseUrl}/api/llm/news-summary`, headers, payload);
  const summary = data?.summary || data?.result || data;
  if (!summary || typeof summary !== 'object') throw new Error('INVALID_STEER_SUMMARY_RESPONSE');
  return JSON.stringify(summary);
};

const normalize = (obj, j, total) => {
  const h = heuristicSummary(j);
  let bullets = (Array.isArray(obj.summary_bullets) ? obj.summary_bullets : [])
    .map((b) => clamp(b, 180))
    .filter((b) => b && !isGarbageLine(b))
    .slice(0, 6);

  if (weakBullets(bullets, j.title || '')) bullets = h.summary_bullets;
  while (bullets.length < 3) bullets.push(h.summary_bullets[bullets.length] || '핵심 요점 보완 필요');

  let why = clamp(obj.why_it_matters || '', 220);
  if (!why || why.length < 28 || !/[가-힣]/.test(why)) why = h.why_it_matters;

  let keywords = (Array.isArray(obj.keywords) ? obj.keywords : [])
    .map((k) => clamp(k, 30))
    .filter((k) => k && !isGarbageLine(k))
    .slice(0, 3);
  if (keywords.length < 3) keywords = keywordFromText(j.title || '').slice(0, 3);
  while (keywords.length < 3) keywords.push(['AI', '시장', '동향'][keywords.length]);

  return {
    title: clamp(obj.title || j.title || h.title, 220),
    link: clamp(obj.link || j.link || h.link, 500),
    source: clamp(obj.source || j.source || h.source, 120),
    pubDate: clamp(obj.pubDate || j.pubDate || h.pubDate, 120),
    summary_bullets: bullets.slice(0, 6),
    why_it_matters: why,
    keywords: keywords.slice(0, 3),
    transparency_note: NOTE,
    scope_marker: clamp(j.scope_marker || obj.scope_marker || '', 120),
    telegram_chat_id: String(j.telegram_chat_id || obj.telegram_chat_id || ''),
    article_count: Number(j.article_count || obj.article_count || total || 5),
  };
};

const out = [];
for (const item of rows) {
  const j = item.json || {};
  const prompt = makePrompt(j);
  const attempts = [];
  let parsed = null;
  let providerUsed = '';

  const providers = [
    {
      name: 'steer-cli-bridge',
      enabled: STEER_SUMMARY_BRIDGE_ENABLED,
      run: async () => callSteerSummaryBridge({
        baseUrl: STEER_API_BASE_URL,
        apiKey: STEER_API_KEY,
        article: j,
      }),
    },
    { name: 'openai', enabled: Boolean(OPENAI_API_KEY), run: async () => callOpenAI({ apiKey: OPENAI_API_KEY, model: OPENAI_MODEL, prompt }) },
    { name: 'gemini', enabled: Boolean(GEMINI_API_KEY), run: async () => callGemini({ apiKey: GEMINI_API_KEY, model: GEMINI_MODEL, prompt }) },
    { name: 'codex', enabled: Boolean(CODEX_API_KEY), run: async () => callOpenAI({ apiKey: CODEX_API_KEY, model: CODEX_MODEL, prompt }) },
    { name: 'llama.cpp', enabled: ENABLE_LOCAL_LLAMACPP_FALLBACK, run: async () => callLlamaCpp({ baseUrl: LLAMACPP_BASE_URL, model: LLAMACPP_MODEL, prompt }) },
  ];

  for (const p of providers) {
    if (!p.enabled) {
      attempts.push(`${p.name}:SKIP_NO_CONFIG`);
      continue;
    }
    try {
      const content = await p.run();
      const candidate = parseJsonSafely(content);
      if (!candidate || typeof candidate !== 'object') {
        attempts.push(`${p.name}:NON_JSON_FALLBACK`);
        parsed = heuristicSummary(j);
      } else {
        attempts.push(`${p.name}:OK`);
        parsed = normalize(candidate, j, rows.length);
      }
      providerUsed = p.name;
      break;
    } catch (err) {
      attempts.push(`${p.name}:FAIL:${clamp(err?.message || String(err), 220)}`);
    }
  }

  if (!parsed) {
    parsed = heuristicSummary(j);
    providerUsed = 'heuristic';
    attempts.push('heuristic:OK');
  }

  out.push({
    json: {
      ...j,
      llm_provider: providerUsed,
      llm_attempts: attempts,
      summary_struct: parsed,
      content: JSON.stringify(parsed),
    },
  });
}

return out;

const parseJsonSafely = (text) => {
  try { return JSON.parse(text); } catch {}
  const m = text.match(/\{[\s\S]*\}/);
  if (m) {
    try { return JSON.parse(m[0]); } catch {}
  }
  return null;
};

const clean = (s, n = 220) => String(s || '').replace(/\s+/g, ' ').trim().slice(0, n);
const containsJsonArtifact = (s) => /(^[\s]*[\{\[\"]|"(title|link|source|pubDate|summary_bullets|why_it_matters|keywords)"\s*:)/i.test(String(s || ''));

const toKeywords = (title, description, topic = '') => {
  const source = `${title || ''} ${description || ''}`
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .split(/\s+/)
    .map((w) => w.trim())
    .filter((w) => w.length >= 2)
    .slice(0, 12);
  const uniq = [];
  for (const w of source) {
    if (!uniq.includes(w)) uniq.push(w);
    if (uniq.length >= 3) break;
  }
  const fallbackTopic = clean(topic || '뉴스', 30);
  while (uniq.length < 3) uniq.push([fallbackTopic, '트렌드', '요약'][uniq.length]);
  return uniq.slice(0, 3).map((w) => clean(w, 30));
};

const fallbackSummary = (item, idx) => {
  const title = clean(item.title || `기사 ${idx + 1}`, 220);
  const description = clean(item.description || '', 400);
  const source = clean(item.source || 'Unknown', 120);
  const pubDate = clean(item.pubDate || '', 120);
  const descShort = description || 'RSS 본문이 짧아 제목 중심으로 요약했습니다.';
  const topic = clean(item.topic || item.topic_label || '뉴스', 80);

  const bullets = [
    `핵심: ${title}`,
    `내용: ${descShort.slice(0, 170)}`,
    `출처/시점: ${source}${pubDate ? `, ${pubDate}` : ''}`,
    `영향: ${topic} 의사결정에 참고 가능한 신호를 제공합니다.`,
  ].map((b) => clean(b, 190));

  return {
    title,
    link: clean(item.link || '', 500),
    source,
    pubDate,
    summary_bullets: bullets,
    why_it_matters: clean(`${title} 이슈는 ${topic} 맥락의 우선순위와 실행 전략에 영향을 줄 수 있습니다.`, 220),
    keywords: toKeywords(title, description, topic),
    transparency_note: '원문 접근 제한: RSS title/description 기반 요약',
    scope_marker: clean(item.scope_marker || '', 120),
    telegram_chat_id: String(item.telegram_chat_id || ''),
    article_count: Number(item.article_count || 5),
    request_source: clean(item.request_source || 'program', 30),
    topic,
    include_youtube: item.include_youtube !== false,
  };
};

const isLowQuality = (obj) => {
  if (!obj || typeof obj !== 'object') return true;
  const bullets = Array.isArray(obj.summary_bullets)
    ? obj.summary_bullets.map((b) => clean(b, 190)).filter(Boolean)
    : [];
  if (bullets.length < 3) return true;
  if (bullets.some((b) => containsJsonArtifact(b))) return true;
  if (clean(bullets.join(' '), 1000).length < 140) return true;

  const why = clean(obj.why_it_matters || '', 240);
  if (!why || why.length < 28 || containsJsonArtifact(why)) return true;

  const keywords = Array.isArray(obj.keywords)
    ? obj.keywords.map((k) => clean(k, 30)).filter(Boolean)
    : [];
  if (keywords.length < 3) return true;
  if (keywords.some((k) => containsJsonArtifact(k))) return true;
  return false;
};

const rows = $input.all();
const out = rows.map((item, idx) => {
  const content = String(item.json?.message?.content || item.json?.content || item.json?.text || '').trim();
  let parsed = parseJsonSafely(content);
  if (!parsed || typeof parsed !== 'object' || isLowQuality(parsed)) {
    parsed = fallbackSummary(item.json || {}, idx);
  }

  const bullets = Array.isArray(parsed.summary_bullets)
    ? parsed.summary_bullets.map((b) => clean(b, 190)).filter(Boolean).slice(0, 6)
    : [];
  while (bullets.length < 3) bullets.push('핵심 요점 보완 필요');

  const title = clean(parsed.title || item.json.title || `기사 ${idx + 1}`, 220);
  const topic = clean(parsed.topic || item.json.topic || item.json.topic_label || '뉴스', 80);
  const keywords = Array.isArray(parsed.keywords)
    ? parsed.keywords.map((k) => clean(k, 30)).filter(Boolean).slice(0, 3)
    : toKeywords(title, item.json.description || '', topic);
  while (keywords.length < 3) keywords.push([topic || '뉴스', '트렌드', '요약'][keywords.length]);

  return {
    json: {
      title,
      link: clean(parsed.link || item.json.link || '', 500),
      source: clean(parsed.source || item.json.source || 'Unknown', 120),
      pubDate: clean(parsed.pubDate || item.json.pubDate || '', 120),
      description: clean(item.json.description || '', 500),
      summary_bullets: bullets,
      why_it_matters: clean(parsed.why_it_matters || '왜 중요한지 정보 없음', 220),
      keywords: keywords.slice(0, 3),
      transparency_note: clean(parsed.transparency_note || '원문 접근 제한: RSS title/description 기반 요약', 180),
      youtube_link: `https://www.youtube.com/results?search_query=${encodeURIComponent(title)}`,
      scope_marker: clean(parsed.scope_marker || item.json.scope_marker || '', 120),
      telegram_chat_id: (() => { const cid = String(item.json.telegram_chat_id || '').trim(); return /^-?\d+$/.test(cid) ? cid : ''; })(),
      article_count: Number(parsed.article_count || item.json.article_count || rows.length || 5),
      request_source: clean(parsed.request_source || item.json.request_source || 'program', 30),
      topic,
      topic_label: topic,
      include_youtube: parsed.include_youtube !== false && item.json.include_youtube !== false,
    },
  };
});

return out;

const rows = $input.all().map(i => i.json).filter(r => r && (r.title || r.link));
if (!rows.length) throw new Error('No summarized rows to aggregate');
const desired = Number(rows[0].article_count || 5);
const N = Math.max(1, Math.min(10, desired));
const articles = rows.slice(0, N);
const topic = String(rows[0].topic || rows[0].topic_label || '최신 이슈').trim() || '최신 이슈';
const includeYoutube = rows[0].include_youtube !== false;

return [{
  json: {
    scope_marker: rows[0].scope_marker || '',
    telegram_chat_id: String(rows[0].telegram_chat_id || ''),
    request_source: String(rows[0].request_source || 'program'),
    article_count: N,
    digest_date: new Date().toISOString().slice(0, 10),
    topic,
    topic_label: topic,
    include_youtube: includeYoutube,
    articles,
  },
}];

const j = $input.first().json;
const articles = Array.isArray(j.articles) ? j.articles : [];
if (!articles.length) throw new Error('No articles for Notion build');

const t = (content, url = '') => {
  const text = { content: String(content || '').slice(0, 1900) };
  if (url) text.link = { url };
  return { type: 'text', text };
};

const blocks = [];
const lines = [];
const topicLabel = String(j.topic_label || j.topic || 'AI').trim() || 'AI';
const includeYoutube = j.include_youtube !== false;

const markerLine = `SCOPE_MARKER: ${j.scope_marker}`;
blocks.push({
  object: 'block',
  type: 'code',
  code: {
    language: 'plain text',
    rich_text: [t(markerLine)],
  },
});
lines.push(markerLine);

const digestTitle = `오늘의 ${topicLabel} Digest (${j.digest_date})`;
blocks.push({
  object: 'block',
  type: 'heading_1',
  heading_1: { rich_text: [t(digestTitle)] },
});
lines.push(digestTitle);

articles.forEach((a, idx) => {
  const heading = `기사 ${idx + 1}. ${a.title}`;
  blocks.push({
    object: 'block',
    type: 'heading_2',
    heading_2: { rich_text: [t(heading)] },
  });

  blocks.push({
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [
        t('원문 링크: '),
        t('기사 원문 열기', a.link),
      ],
    },
  });

  if (includeYoutube) {
    blocks.push({
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [
          t('YouTube 링크: '),
          t('검색 바로가기', a.youtube_link),
        ],
      },
    });
  }

  const bullets = Array.isArray(a.summary_bullets) ? a.summary_bullets : [];
  bullets.forEach((bullet) => {
    blocks.push({
      object: 'block',
      type: 'bulleted_list_item',
      bulleted_list_item: {
        rich_text: [t(String(bullet || '').trim())],
      },
    });
  });

  blocks.push({
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [
        t('왜 중요한가: '),
        t(a.why_it_matters),
      ],
    },
  });

  blocks.push({
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [
        t('키워드: '),
        t((Array.isArray(a.keywords) ? a.keywords : []).join(', ')),
      ],
    },
  });

  if (a.transparency_note) {
    blocks.push({
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [
          t('참고: '),
          t(a.transparency_note),
        ],
      },
    });
  }

  if (idx < articles.length - 1) {
    blocks.push({ object: 'block', type: 'divider', divider: {} });
  }

  lines.push(heading);
  lines.push(`원문 링크: ${a.link}`);
  if (includeYoutube) lines.push(`YouTube 링크: ${a.youtube_link}`);
  bullets.forEach((b) => lines.push(`- ${String(b || '').trim()}`));
  lines.push(`왜 중요한가: ${a.why_it_matters}`);
  lines.push(`키워드: ${(Array.isArray(a.keywords) ? a.keywords : []).join(', ')}`);
  if (a.transparency_note) lines.push(`참고: ${a.transparency_note}`);
  lines.push('');
});

const notion_text = lines.join('\n').trim();
const top_headlines = articles.slice(0, 5).map((a) => a.title);
const top_headlines_text = top_headlines.map((h, i) => `${i + 1}. ${h}`).join('\n');

return [{
  json: {
    ...j,
    topic_label: topicLabel,
    include_youtube: includeYoutube,
    digest_title: digestTitle,
    notion_text,
    notion_children: blocks.slice(0, 95),
    top_headlines,
    top_headlines_text,
  },
}];

const input = $input.first().json;
const ENV = typeof $env === 'object' && $env ? $env : {};
const token = String(ENV.NOTION_API_TOKEN || '').trim();
if (!token) {
  throw new Error('NOTION_API_TOKEN missing');
}

const parentPageId = '305ac3aa760580ba8991c6338e6f9332';
const notionVersion = '2022-06-28';

const request = async (method, url, body) => {
  const options = {
    method,
    url,
    headers: {
      Authorization: `Bearer ${token}`,
      'Notion-Version': notionVersion,
      'Content-Type': 'application/json',
    },
    json: true,
    timeout: 60000,
  };
  if (body) options.body = body;

  if (typeof this !== 'undefined' && this?.helpers?.httpRequest) {
    return await this.helpers.httpRequest(options);
  }
  if (typeof $httpRequest === 'function') {
    return await $httpRequest(options);
  }
  throw new Error('HTTP_HELPER_NOT_AVAILABLE');
};

const fallbackTopic = String(input.topic_label || input.topic || "뉴스").trim() || "뉴스";
const title = String(input.digest_title || `오늘의 ${fallbackTopic} Digest (${new Date().toISOString().slice(0, 10)})`).slice(0, 200);
let children = Array.isArray(input.notion_children) ? input.notion_children : [];

if (!children.length) {
  const fallbackText = String(input.notion_text || '').trim();
  if (!fallbackText) {
    throw new Error('No Notion content available');
  }
  children = [{
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [
        {
          type: 'text',
          text: { content: fallbackText.slice(0, 1900) },
        },
      ],
    },
  }];
}

children = children.slice(0, 95);

const body = {
  parent: { page_id: parentPageId },
  properties: {
    title: {
      title: [
        {
          type: 'text',
          text: { content: title },
        },
      ],
    },
  },
  children,
};

const created = await request('POST', 'https://api.notion.com/v1/pages', body);

return [{
  json: {
    ...input,
    id: created.id,
    url: created.url,
  },
}];
